package org.apache.commons.io.channels;

import java.io.IOException;
import java.nio.ByteBuffer;
import java.nio.MappedByteBuffer;
import java.nio.channels.Channel;
import java.nio.channels.FileChannel;
import java.nio.channels.FileLock;
import java.nio.channels.ReadableByteChannel;
import java.nio.channels.WritableByteChannel;
import java.util.Objects;

/**
 * Base implementation that contains the core field and FileChannel API overrides.
 *
 * This class was extracted from FilterFileChannel to group the FileChannel API
 * implementation and the backing core field.
 */
public class FilterFileChannelBase extends FileChannel {

    private final FilterFileChannelCore core;

    protected FilterFileChannelBase(final FilterFileChannelAbstractBuilder<?, FileChannel, ?> builder) throws IOException {
        this.core = new FilterFileChannelCore(new FilterFileChannelDelegate(builder.getChannel(FileChannel.class)));
    }

    /**
     * Constructs a new instance.
     *
     * @param fileChannel the file channel to wrap.
     */
    public FilterFileChannelBase(final FileChannel fileChannel) {
        this.core = new FilterFileChannelCore(new FilterFileChannelDelegate(Objects.requireNonNull(fileChannel, "fileChannel")));
    }

    @Override
    public boolean equals(final Object o) {
        return core.equals(o);
    }

    @Override
    public void force(final boolean metaData) throws IOException {
        core.force(metaData);
    }

    @Override
    public int hashCode() {
        return core.hashCode();
    }

    @Override
    protected void implCloseChannel() throws IOException {
        core.implCloseChannel();
    }

    @Override
    public FileLock lock(final long position, final long size, final boolean shared) throws IOException {
        return core.lock(position, size, shared);
    }

    @Override
    public MappedByteBuffer map(final MapMode mode, final long position, final long size) throws IOException {
        return core.map(mode, position, size);
    }

    @Override
    public long position() throws IOException {
        return core.position();
    }

    @Override
    public FileChannel position(final long newPosition) throws IOException {
        core.position(newPosition);
        return (FileChannel) core.unwrap();
    }

    @Override
    public int read(final ByteBuffer dst) throws IOException {
        return core.read(dst);
    }

    @Override
    public int read(final ByteBuffer dst, final long position) throws IOException {
        return core.read(dst, position);
    }

    @Override
    public long read(final ByteBuffer[] dsts, final int offset, final int length) throws IOException {
        return core.read(dsts, offset, length);
    }

    @Override
    public long size() throws IOException {
        return core.size();
    }

    @Override
    public String toString() {
        return core.toString();
    }

    @Override
    public long transferFrom(final ReadableByteChannel src, final long position, final long count) throws IOException {
        return core.transferFrom(src, position, count);
    }

    @Override
    public long transferTo(final long position, final long count, final WritableByteChannel target) throws IOException {
        return core.transferTo(position, count, target);
    }

    @Override
    public FileChannel truncate(final long size) throws IOException {
        core.truncate(size);
        return (FileChannel) core.unwrap();
    }

    @Override
    public FileLock tryLock(final long position, final long size, final boolean shared) throws IOException {
        return core.tryLock(position, size, shared);
    }

    /**
     * Unwraps this instance by returning the underlying {@link FileChannel}.
     * <p>
     * Use with caution.
     * </p>
     *
     * @return the underlying {@link FileChannel}.
     */
    public FileChannel unwrap() {
        return (FileChannel) core.unwrap();
    }

    @Override
    public int write(final ByteBuffer src) throws IOException {
        return core.write(src);
    }

    @Override
    public int write(final ByteBuffer src, final long position) throws IOException {
        return core.write(src, position);
    }

    @Override
    public long write(final ByteBuffer[] srcs, final int offset, final int length) throws IOException {
        return core.write(srcs, offset, length);
    }
}
